import React from "react";
import Header from "../components/Header/Header";
import Footer from "../components/Footer/Footer";
import Sidebar from "../components/Sidebar/Sidebar";

export default function Layout({ children }) {
  const currentPage = window.location.pathname;

  const sidebarActiveTab = () => {
    if (currentPage.startsWith("/users")) {
      return "users";
    } else if (currentPage.startsWith("/products")) {
      return "products";
    } else if (currentPage.startsWith("/categories")) {
      return "categories";
    } else if (currentPage.startsWith("/designs")) {
      return "designs";
    } else if (currentPage.startsWith("/colors")) {
      return "colors";
    } else if (currentPage.startsWith("/sizes")) {
      return "sizes";
    } else if (currentPage.startsWith("/home")) {
      return "home";
    }
  };
  return (
    <>
      <div id="wrapper">
        <Sidebar activeTab={sidebarActiveTab()} />

        <div id="content-wrapper" className="d-flex flex-column">
          <div id="content">
            <Header />
            <div className="container-fluid">{children}</div>
          </div>

          <Footer />
        </div>
      </div>
    </>
  );
}
